INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Clean', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'compound', ARRAY['Begin standing with a dumbbell in each hand with your feet shoulder width apart.','Lower the weights to the floor by flexing at the hips and knees, pushing your hips back until the dumbbells reach the floor. This will be your starting position.','To initiate the movement, violently jump upward by extending the hips, knees, and ankles to acclerate the weights upward. Maintaining a neutral grip on the dumbbells, keep the arms straight until full extension is reached.','After full extension, rebend the hips and knees to receive the weight in a squat position. Allow the arms to bend, guiding the dumbbells to your shoulders.','Upon receiving the weight in the squat position, extend the hips and knees to finish in a standing position with the weights on your shoulders.'], ARRAY['hamstrings'], ARRAY['calves','forearms','glutes','lower back','quadriceps','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Floor Press', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Lay on the floor holding dumbbells in your hands. Your knees can be bent. Begin with the weights fully extended above you.','Lower the weights until your upper arm comes in contact with the floor. You can tuck your elbows to emphasize triceps size and strength, or to focus on your chest angle your arms to the side.','Pause at the bottom, and then bring the weight together at the top by extending through the elbows.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Flyes', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Lie down on a flat bench with a dumbbell on each hand resting on top of your thighs. The palms of your hand will be facing each other.','Then using your thighs to help raise the dumbbells, lift the dumbbells one at a time so you can hold them in front of you at shoulder width with the palms of your hands facing each other. Raise the dumbbells up like you''re pressing them, but stop and hold just before you lock out. This will be your starting position.','With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.','Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.','Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Incline Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Using a neutral grip, lean into an incline bench.','Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position.','Retract the shoulder blades and flex the elbows to row the dumbbells to your side.','Pause at the top of the motion, and then return to the starting position.'], ARRAY['middle back'], ARRAY['biceps','forearms','lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Incline Shoulder Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Sit on an Incline Bench while holding a dumbbell on each hand on top of your thighs.','Lift your legs up to kick the weights to your shoulders and lean back. Position the dumbbells above your shoulders with your arms extended. The arms should be perpendicular to the floor with your palms facing forward and knuckles pointing towards the ceiling. This will be your starting position.','While keeping the arms straight and locked, lift the dumbbells by raising the shoulders from the bench as you breathe out.','Bring back the dumbbells to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Lunges', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.','Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.','Using mainly the heel of your foot, push up and go back to the starting position as you exhale.','Repeat the movement for the recommended amount of repetitions and then perform with the left leg.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY['Long step forward, both knees to 90 degrees','Lower straight down, dont lean forward','Push through front heel to stand','Keep torso upright entire time','Back knee should nearly touch floor'], ARRAY['Step too short','Front knee shooting past toes','Leaning forward excessively','Losing balance'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Lying One-Arm Rear Lateral Raise', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['While holding a dumbbell in one hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench. The other hand can be used to hold to the leg of the bench for stability.','Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.','Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.','Slowly lower the dumbbell to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Lying Pronation', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Lie on a flat bench face down with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.','Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.','Now raise the upper arm so that the forearm is perpendicular to the floor and the upper arm is perpendicular to your torso. Tip: The upper arm should be parallel to the floor and also creating a 90-degree angle with your torso. This will be your starting position.','As you breathe out, externally rotate your forearm so that the dumbbell is lifted forward as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is parallel to the floor. At this point you will hold the contraction for a second.','As you breathe in, slowly go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Lying Rear Lateral Raise', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['While holding a dumbbell in each hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench.','Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.','Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.','Slowly lower the dumbbells to the starting position as you inhale.','Repeat for the recommended amount of repetitions and then switch to the other arm.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Lying Supination', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.','Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.','Now raise the upper arm so that the forearm is parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.','As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.','As you breathe in, slowly go back to the starting position.','Repeat for the recommended amount of repetitions and then switch to the other arm.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell One-Arm Shoulder Press', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.','Clean the dumbbell up to bring it to shoulder height. The other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface.','Rotate the wrist so that the palm of your hand is facing forward. This is your starting position.','As you exhale, push the dumbbell up until your arm is fully extended.','After a second pause, slowly come down back to the starting position as you inhale.','Repeat for the recommended amount of repetitions and then switch arms.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell One-Arm Triceps Extension', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.','Clean the dumbbell up to bring it to shoulder height and then extend the arm over your head so that the whole arm is perpendicular to the floor and next to your head. The dumbbell should be on top of you. The other hand can be kept fully extended to the side, by the waist, supporting the upper arm that has the dumbbell or grabbing a fixed surface.','Rotate the wrist so that the palm of your hand is facing forward and the pinkie is facing the ceiling. This will be your starting position.','Slowly lower the dumbbell behind your head as you hold the upper arm stationary. Inhale as you perform this movement and pause when your triceps are fully stretched.','Return to the starting position by flexing your triceps as you breathe out. Tip: It is imperative that only the forearm moves. The upper arm should remain at all times stationary next to your head.','Repeat for the recommended amount of repetitions and switch arms.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell One-Arm Upright Row', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'compound', ARRAY['Grab a dumbbell and stand up straight with your arm extended in front of you with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be resting on top of your thigh with the palm of your hands facing your thighs.','Keep the other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface. This will be your starting position.','Use your side shoulders to lift the dumbbell as you exhale. The dumbbell should be close to the body as you move it up. Continue to lift it until the dumbbell is nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the dumbbell back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions and switch arms.'], ARRAY['shoulders'], ARRAY['biceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Prone Incline Curl', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Grab a dumbbell on each hand and lie face down on an incline bench with your shoulders near top of the incline. Your knees can rest on the seat or your legs can be straddled to the sides (my preferred way).','Let your arms extend and hang naturally in front of you so that they are perpendicular to the floor.','Now keep your elbows in by your side and face the palms forward. This will be your starting position.','Raise the dumbbells by contracting the biceps until your arms are fully flexed. Exhale as you perform this portion of the movement and ensure that only the forearms move. The upper arms should remain stationary at all times.','Lower the dumbbells until your arms are fully extended.','Repeat for the recommended amount of times.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Grab a dumbbell in each arm and stand up straight with your arms extended by your sides with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be next to your thighs with the palm of your hands facing back.','Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be to the side of the body as you move them up. Continue to lift it until the dumbbells are nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['biceps'], ARRAY['Slight bend in elbows, lift to shoulder height','Lead with elbows, not hands','Thumbs slightly tilted down like pouring water','Control the descent, dont just drop','Use lighter weight with perfect form'], ARRAY['Swinging body to get weight up','Going above shoulder height','Using too much weight','Shrugging shoulders up'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Rear Lunge', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.','Step backward with your right leg around two feet or so from the left foot and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Tip: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Keep the torso upright during the lunge; flexible hip flexors are important. A long lunge emphasizes the Gluteus Maximus; a short lunge emphasizes Quadriceps.','Push up and go back to the starting position as you exhale. Tip: Use the ball of your feet to push in order to accentuate the quadriceps. To focus on the glutes, press with your heels.','Now repeat with the opposite leg.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Scaption', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['This corrective exercise strengthens the muscles that stabilize your shoulder blade. Hold a light weight in each hand, hanging at your sides. Your thumbs should pointing up.','Begin the movement raising your arms out in front of you, about 30 degrees off center. Your arms should be fully extended as you perform the movement.','Continue until your arms are parallel to the ground, and then return to the starting position.'], ARRAY['shoulders'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Seated Box Jump', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Position a box a couple feet to the side of a bench. Hold a dumbbell to your chest with both hands and seat yourself on the bench facing the box. This will be your starting position.','Plant your feet firmly on the ground as you lean forward, extending through the hips and knees to jump up and forward.','Land on the box with both feet, absorbing the impact by allowing the hips and knees to bend.','Step down and return to the starting position.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Seated One-Leg Calf Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Place a block on the floor about 12 inches from a flat bench.','Sit on a flat bench and place a dumbbell on your upper left thigh about 3 inches above your knee.','Now place the ball of your left foot on the block. This will be your starting position.','Raise your toes up as high as possible as you exhale and you contract your calf muscle. Hold the contraction for a second.','Slowly return to the starting position, stretching as far down as possible.','Repeat for your prescribed number of repetitions and then repeat with the right leg.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Shoulder Press', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['While holding a dumbbell in each hand, sit on a military press bench or utility bench that has back support. Place the dumbbells upright on top of your thighs.','Now raise the dumbbells to shoulder height one at a time using your thighs to help propel them up into position.','Make sure to rotate your wrists so that the palms of your hands are facing forward. This is your starting position.','Now, exhale and push the dumbbells upward until they touch at the top.','Then, after a brief pause at the top contracted position, slowly lower the weights back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Shrug', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand erect with a dumbbell on each hand (palms facing your torso), arms extended on the sides.','Lift the dumbbells by elevating the shoulders as high as possible while you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the dumbbells. Only the shoulders should be moving up and down.','Lower the dumbbells back to the original position.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Side Bend', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up straight while holding a dumbbell on the left hand (palms facing the torso) as you have the right hand holding your waist. Your feet should be placed at shoulder width. This will be your starting position.','While keeping your back straight and your head up, bend only at the waist to the right as far as possible. Breathe in as you bend to the side. Then hold for a second and come back up to the starting position as you exhale. Tip: Keep the rest of the body stationary.','Now repeat the movement but bending to the left instead. Hold for a second and come back to the starting position.','Repeat for the recommended amount of repetitions and then change hands.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Squat', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).','Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.','Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until your thighs are parallel to the floor. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise your torso as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Squat To A Bench', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Stand up straight with a flat bench behind you while holding a dumbbell on each hand (palms facing the side of your legs).','Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.','Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until you slightly touch the bench behind you. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Step Ups', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).','Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up.','Step down with the left leg by flexing the hip and knee of the right leg as you inhale. Return to the original standing position by placing the right foot of to next to the left foot on the initial position.','Repeat with the right leg for the recommended amount of repetitions and then perform with the left leg.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Tricep Extension -Pronated Grip', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Lie down on a flat bench holding two dumbbells directly above your shoulders. Your arms should be fully extended and form a 90 degree angle from your torso and the floor.','The palms of your hands should be facing forward, and your elbows should be tucked in. This will be your starting position.','Now, inhale and slowly lower the dumbbells until they are near your ears. Be sure to keep your upper arms stationary and your elbows tucked in.','Then, exhale and use your triceps to return the weight to the starting position.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('EZ-Bar Curl', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'pull', 'isolation', ARRAY['Stand up straight while holding an EZ curl bar at the wide outer handle. The palms of your hands should be facing forward and slightly tilted inward due to the shape of the bar. Keep your elbows close to your torso. This will be your starting position.','Now, while keeping your upper arms stationary, exhale and curl the weights forward while contracting the biceps. Focus on only moving your forearms.','Continue to raise the weight until your biceps are fully contracted and the bar is at shoulder level. Hold the top contracted position for a moment and squeeze the biceps.','Then inhale and slowly lower the bar back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('EZ-Bar Skullcrusher', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'push', 'isolation', ARRAY['Using a close grip, lift the EZ bar and hold it with your elbows in as you lie on the bench. Your arms should be perpendicular to the floor. This will be your starting position.','Keeping the upper arms stationary, lower the bar by allowing the elbows to flex. Inhale as you perform this portion of the movement. Pause once the bar is directly above the forehead.','Lift the bar back to the starting position by extending the elbow and exhaling.','Repeat.'], ARRAY['triceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Elbow to Knee', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position.','Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee.','Return to the starting position and repeat the movement for the desired number of repetitions before switching sides.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Elevated Back Lunge', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Position a bar onto a rack at shoulder height loaded to an appropriate weight. Place a short, raised platform behind you.','Rack the bar onto your upper back, keeping your back arched and tight. Step onto your raised platform with both feet. This will be your starting position.','Begin by stepping backwards with one leg. Descend by flexing your hips and knees until your knee touches the floor.','Pause, and extend through the hips and knees to rise up, returning all the way to the starting position before alternating.'], ARRAY['quadriceps'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Elevated Cable Rows', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['Get a platform of some sort (it can be an aerobics or calf raise platform) that is around 4-6 inches in height.','Place it on the seat of the cable row machine.','Sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.','Lean over as you keep the natural alignment of your back and grab the V-bar handles.','With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.','Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.','Repeat for the recommended amount of repetitions.'], ARRAY['lats'], ARRAY['middle back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Elliptical Trainer', 'machine', true, 'machine', 'intermediate', NULL, NULL, ARRAY['To begin, step onto the elliptical and select the desired option from the menu. Most ellipticals have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Exercise Ball Crunch', 'exercise ball', true, 'exercise ball', 'beginner', 'pull', 'isolation', ARRAY['Lie on an exercise ball with your lower back curvature pressed against the spherical surface of the ball. Your feet should be bent at the knee and pressed firmly against the floor. The upper torso should be hanging off the top of the ball. The arms should either be kept alongside the body or crossed on top of your chest as these positions avoid neck strains (as opposed to the hands behind the back of the head position).','Lower your torso into a stretch position keeping the neck stationary at all times. This will be your starting position.','With the hips stationary, flex the waist by contracting the abdominals and curl the shoulders and trunk upward until you feel a nice contraction on your abdominals. The arms should simply slide up the side of your legs if you have them at the side or just stay on top of your chest if you have them crossed. The lower back should always stay in contact with the ball. Exhale as you perform this movement and hold the contraction for a second.','As you inhale, go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Exercise Ball Pull-In', 'exercise ball', true, 'exercise ball', 'beginner', 'pull', 'compound', ARRAY['Place an exercise ball nearby and lay on the floor in front of it with your hands on the floor shoulder width apart in a push-up position.','Now place your lower shins on top of an exercise ball. Tip: At this point your legs should be fully extended with the shins on top of the ball and the upper body should be in a push-up type of position being supported by your two extended arms in front of you. This will be your starting position.','While keeping your back completely straight and the upper body stationary, pull your knees in towards your chest as you exhale, allowing the ball to roll forward under your ankles. Squeeze your abs and hold that position for a second.','Now slowly straighten your legs, rolling the ball back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Extended Range One-Arm Kettlebell Floor Press', 'kettlebells', true, 'kettlebells', 'beginner', 'push', 'compound', ARRAY['Lie on the floor and position a kettlebell for one arm to press. The kettlebell should be held by the handle. The leg on the same side that you are pressing should be bent, with the knee crossing over the midline of the body.','Press the kettlebell by extending the elbow and adducting the arm, pressing it above your body. Return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('External Rotation', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.','Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm. Tip: Keep the arm parallel to your torso.','Now bend the elbow while keeping the upper arm stationary. In this manner, the forearm will be parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.','As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.','As you breathe in, slowly go back to the starting position.','Repeat for the recommended amount of repetitions and then switch to the other arm.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('External Rotation with Band', 'bands', true, 'bands', 'beginner', 'pull', 'compound', ARRAY['Choke the band around a post. The band should be at the same height as your elbow. Stand with your left side to the band a couple of feet away.','Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.','With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching across the front of your torso. This will be your starting position.','Execute the movement by rotating your arm in a backhand motion, keeping your elbow in place.','Continue as far as you are able, pause, and then return to the starting position.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('External Rotation with Cable', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Adjust the cable to the same height as your elbow. Stand with your left side to the band a couple of feet away.','Grasp the handle with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.','With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching across the front of your torso. This will be your starting position.','Execute the movement by rotating your arm in a backhand motion, keeping your elbow in place.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Face Pull', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['Facing a high pulley with a rope or dual handles attached, pull the weight directly towards your face, separating your hands as you do so. Keep your upper arms parallel to the ground.'], ARRAY['shoulders'], ARRAY['middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Farmer''s Walk', 'other', true, 'other', 'intermediate', NULL, 'compound', ARRAY['There are various implements that can be used for the farmers walk. These can also be performed with heavy dumbbells or short bars if these implements aren''t available. Begin by standing between the implements.','After gripping the handles, lift them up by driving through your heels, keeping your back straight and your head up.','Walk taking short, quick steps, and don''t forget to breathe. Move for a given distance, typically 50-100 feet, as fast as possible.'], ARRAY['forearms'], ARRAY['abdominals','glutes','hamstrings','lower back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Fast Skipping', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Start in a relaxed position with one leg slightly forward. This will be your starting position.','Skip by executing a step-hop pattern of right-right-step to left-left-step, and so on, alternating back and forth.','Perform fast skips by maintaining close contact with the ground and reduce air time, moving as quickly as possible.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Finger Curls', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. This will be your starting position.','Lower the bar as far as possible by extending the fingers. Allowing the bar to roll down the hands, catch the bar with the final joint in the fingers.','Now curl bar up as high as possible by closing your hands while exhaling. Hold the contraction at the top.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Flat Bench Cable Flyes', 'cable', true, 'cable', 'intermediate', 'push', 'isolation', ARRAY['Position a flat bench between two low pulleys so that when you are laying on it, your chest will be lined up with the cable pulleys.','Lay flat on the bench and keep your feet on the ground.','Have someone hand you the handles on each hand. You will grab each single handle attachment with a palms up grip.','Extend your arms by your side with a slight bend on your elbows. Tip: You will keep this bend constant through the whole movement. Your arms should be parallel to the floor. This is your starting position.','Now start lifting the arms in a semi-circle motion directly in front of you by pulling the cables together until both hands meet at the top of the movement. Squeeze your chest as you perform this motion and breathe out during this movement. Also, hold the contraction for a second at the top. Tip: When performed correctly, at the top position of this movement, your arms should be perpendicular to your torso and the floor touching above your chest.','Slowly come back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Flat Bench Leg Pull-In', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie on an exercise mat or a flat bench with your legs off the end.','Place your hands either under your glutes with your palms down or by the sides holding on to the bench (or with palms down by the side on an exercise mat). Also extend your legs straight out. This will be your starting position.','Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue this movement until your knees are near your chest. Hold the contracted position for a second.','As you breathe in, slowly return to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Flat Bench Lying Leg Raise', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie with your back flat on a bench and your legs extended in front of you off the end.','Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position.','As you keep your legs extended, straight as possible with your knees slightly bent but locked raise your legs until they make a 90-degree angle with the floor. Exhale as you perform this portion of the movement and hold the contraction at the top for a second.','Now, as you inhale, slowly lower your legs back down to the starting position.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Flexor Incline Dumbbell Curls', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Hold the dumbbell towards the side farther from you so that you have more weight on the side closest to you. (This can be done for a good effect on all bicep dumbbell exercises). Now do a normal incline dumbbell curl, but keep your wrists as far back as possible so as to neutralize any stress that is placed on them.','Sit on an incline bench that is angled at 45-degrees while holding a dumbbell on each hand.','Let your arms hang down on your sides, with the elbows in, and turn the palms of your hands forward with the thumbs pointing away from the body. Tip: You will keep this hand position throughout the movement as there should not be any twisting of the hands as they come up. This will be your starting position.','Curl up the two dumbbells at the same time until your biceps are fully contracted and exhale. Tip: Do not swing the arms or use momentum. Keep a controlled motion at all times. Hold the contracted position for a second at the top.','As you inhale, slowly go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Floor Glute-Ham Raise', 'body only', true, 'body only', 'intermediate', 'pull', 'isolation', ARRAY['You can use a partner for this exercise or brace your feet under something stable.','Begin on your knees with your upper legs and torso upright. If using a partner, they will firmly hold your feet to keep you in position. This will be your starting position.','Lower yourself by extending at the knee, taking care to NOT flex the hips as you go forward.','Place your hands in front of you as you reach the floor. This movement is very difficult and you may be unable to do it unaided. Use your arms to lightly push off the floor to aid your return to the starting position.'], ARRAY['hamstrings'], ARRAY['calves','glutes'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Floor Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Adjust the j-hooks so they are at the appropriate height to rack the bar. Begin lying on the floor with your head near the end of a power rack. Keeping your shoulder blades pulled together; pull the bar off of the hooks.','Lower the bar towards the bottom of your chest or upper stomach, squeezing the bar and attempting to pull it apart as you do so. Ensure that you tuck your elbows throughout the movement. Lower the bar until your upper arm contacts the ground and pause, preventing any slamming or bouncing of the weight.','Press the bar back up as fast as you can, keeping the bar, your wrists, and elbows in line as you do so.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Floor Press with Chains', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Adjust the j-hooks so they are at the appropriate height to rack the bar. For this exercise, drape the chains directly over the end of the bar, trying to keep the ends away from the plates.','Begin lying on the floor with your head near the end of a power rack. Keeping your shoulder blades pulled together, pull the bar off of the hooks.','Lower the bar towards the bottom of your chest or upper stomach, squeezing the bar and attempting to pull it apart as you do so. Ensure that you tuck your elbows throughout the movement. Lower the bar until your upper arm contacts the ground and pause, preventing any slamming or bouncing of the weight.','Press the bar back up as fast as you can, keeping the bar, your wrists, and elbows in line as you do so.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Flutter Kicks', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['On a flat bench lie facedown with the hips on the edge of the bench, the legs straight with toes high off the floor and with the arms on top of the bench holding on to the front edge.','Squeeze your glutes and hamstrings and straighten the legs until they are level with the hips. This will be your starting position.','Start the movement by lifting the left leg higher than the right leg.','Then lower the left leg as you lift the right leg.','Continue alternating in this manner (as though you are doing a flutter kick in water) until you have done the recommended amount of repetitions for each leg. Make sure that you keep a controlled movement at all times. Tip: You will breathe normally as you perform this movement.'], ARRAY['glutes'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Forward Drag with Press', 'other', true, 'other', 'intermediate', 'push', 'compound', ARRAY['Attach a dual handled chain or rope attachment to the sled. You should be facing away from the sled, holding a handle in each hand.','Begin the movement by moving forward for one step. Leaning forward, extend through the legs and hips to move, pausing with each step to extend through the elbows, pressing your hands forward. Step forward until you return to the start position prepared to press.'], ARRAY['chest'], ARRAY['calves','glutes','hamstrings','quadriceps','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Frankenstein Squat', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['This drill teaches you the proper positioning of both the bar and your body during the clean and front squat.','Place the barbell on the front of the shoulders, releasing your grip and extending your arms out in front of you. The shoulders should be pushed forward to create a shelf, and the bar should be in contact with the throat. Ensure that you only move your shoulder blades forward; don''t round the thoracic spine.','Squat by flexing the knees and hips, sitting in between your legs. Keep the torso upright, the arms up, and the shoulders forward, and the bar should stay in place. Go to the bottom of the squat, until your hamstrings contact your calves.','Return to the upright position by driving through the front of the heel and extending the knees and hips.'], ARRAY['quadriceps'], ARRAY['abdominals','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Freehand Jump Squat', 'body only', true, 'body only', 'intermediate', 'push', 'compound', ARRAY['Cross your arms over your chest.','With your head up and your back straight, position your feet at shoulder width.','Keeping your back straight and chest up, squat down as you inhale until your upper thighs are parallel, or lower, to the floor.','Now pressing mainly with the ball of your feet, jump straight up in the air as high as possible, using the thighs like springs. Exhale during this portion of the movement.','When you touch the floor again, immediately squat down and jump again.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Frog Sit-Ups', 'body only', true, 'body only', 'intermediate', 'pull', 'isolation', ARRAY['Lie with your back flat on the floor (or exercise mat) and your legs extended in front of you.','Now bend at the knees and place your outer thighs by the floor (or mat) as you make the soles of your feet touch each other.','Now try pushing both soles and bringing them up as near you as possible while you keep the outer thighs on the floor (or at least almost touching it). Tip: In this position your legs should create a diamond shape.','Now, cross your arms in front of you by touching the opposite shoulders. This will be your starting position.','As you exhale flatten your lower back to the floor while curling the torso upwards. Tip: This will be like performing the first 1/4 movement of a sit up. Hold at the top position for a second.','As you inhale, slowly lower back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Barbell Squat', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, bring your arms up under the bar while keeping the elbows high and the upper arm slightly above parallel to the floor. Rest the bar on top of the deltoids and cross your arms while grasping the bar for total control.','Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor mainly with the middle of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Barbell Squat To A Bench', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set a flat bench behind you and set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, bring your arms up under the bar while keeping the elbows high and the upper arm slightly above parallel to the floor. Rest the bar on top of the deltoids and cross your arms while grasping the bar for total control.','Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until you touch the bench with your glutes. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor mainly with the heel of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Box Jump', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Begin with a box of an appropriate height 1-2 feet in front of you. Stand with your feet should width apart. This will be your starting position.','Perform a short squat in preparation for jumping, swinging your arms behind you.','Rebound out of this position, extending through the hips, knees, and ankles to jump as high as possible. Swing your arms forward and up.','Land on the box with the knees bent, absorbing the impact through the legs. You can jump from the box back to the ground, or preferably step down one leg at a time.'], ARRAY['hamstrings'], ARRAY['abductors','adductors','calves','glutes','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Cable Raise', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Select the weight on a low pulley machine and grasp the single hand cable attachment that is attached to the low pulley with your left hand.','Face away from the pulley and put your arm straight down with the hand cable attachment in front of your thighs at arms'' length with the palms of the hand facing your thighs. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the left arm to the front with a slight bend on the elbow and the palms of the hand always faces down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.','Now as you inhale lower the arm back down slowly to the starting position.','Once all of the recommended amount of repetitions have been performed for this arm, switch arms and perform the exercise with the right one.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Cone Hops (or hurdle hops)', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Set up a row of cones or other small barriers, placing them a few feet apart.','Stand in front of the first cone with your feet shoulder width apart. This will be your starting position.','Begin by jumping with both feet over the first cone, swinging both arms as you jump.','Absorb the impact of landing by bending the knees, rebounding out of the first leap by jumping over the next cone.','Continue until you have jumped over all of the cones.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Dumbbell Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the left dumbbell to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top. Inhale after the second pause.','Now lower the dumbbell back down slowly to the starting position as you simultaneously lift the right dumbbell.','Continue alternating in this fashion until all of the recommended amount of repetitions have been performed for each arm.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Incline Dumbbell Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Sit down on an incline bench with the incline set anywhere between 30 to 60 degrees while holding a dumbbell on each hand. Tip: You can change the angle to hit the muscle a little differently each time.','Extend your arms straight in front of you and have your palms facing down with the dumbbells raised about 1 inch above your thighs. This will be your starting position.','Slowly raise the dumbbells straight up until they are slightly above your shoulders, while keeping your elbows locked. Squeeze at the top for a second and make sure you breathe out during this portion of the movement. Tip: Keep your head resting down against the bench and your legs on the floor at all times.','Lower the arms back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Plate Raise', 'other', true, 'other', 'intermediate', 'push', 'isolation', ARRAY['While standing straight, hold a barbell plate in both hands at the 3 and 9 o''clock positions. Your palms should be facing each other and your arms should be extended and locked with a slight bend at the elbows and the plate should be down near your waist in front of you as far as you can go. Tip: The arms will remain in this position throughout the exercise. This will be your starting position.','Slowly raise the plate as you exhale until it is a little above shoulder level. Hold the contraction for a second. Tip: make sure that you do not swing the weight or bend at the elbows. Your torso should remain stationary throughout the movement as well.','As you inhale, slowly lower the plate back down to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Raise And Pullover', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Lie on a flat bench while holding a barbell using a palms down grip that is about 15 inches apart.','Place the bar on your upper thighs, extend your arms and lock them while keeping a slight bend on the elbows. This will be your starting position.','Now raise the weight using a semicircular motion and keeping your arms straight as you inhale. Continue the same movement until the bar is on the other side above your head . (Tip: the bar will travel approximately 180-degrees). At this point your arms should be parallel to the floor with the palms of your hands facing the ceiling.','Now return the barbell to the starting position by reversing the motion as you exhale.','Repeat for the recommended amount of repetitions.'], ARRAY['chest'], ARRAY['lats','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Squat (Clean Grip)', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['To begin, first set the bar in a rack slightly below shoulder level. Rest the bar on top of the deltoids, pushing into the clavicles, and lightly touching the throat. Your hands should be in a clean grip, touching the bar only with your fingers to help keep it in position.','Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso. Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head and elbows up at all times. This will be your starting position.','Bend at the knees, sitting down between your legs. Continue down until your hamstrings are on your calves. Keep your knees aligned with your feet by consciously using your abductors to push your knees out as you squat.','Begin to raise the bar as you exhale by pushing the floor mainly with the heel or middle of your foot as you straighten the legs again and return to the starting position.'], ARRAY['quadriceps'], ARRAY['abdominals','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Squats With Two Kettlebells', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so.','Looking straight ahead at all times, squat as low as you can and pause at the bottom. As you squat down, push your knees out. You should squat between your legs, keeping an upright torso, with your head and chest up.','Rise back up by driving through your heels and repeat.'], ARRAY['quadriceps'], ARRAY['calves','glutes'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Front Two-Dumbbell Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the dumbbells to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arms are slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.','As you inhale, lower the dumbbells back down slowly to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Full Range-Of-Motion Lat Pulldown', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['Either standing or seated on a high bench, grasp two stirrup cables that are attached to the high pulleys. Grab with the opposing hand so your arms are crisscrossed about you and your palms are facing forward.','Keeping your chest up and maintaining a slight arch in your lower back, pull the handles down as if you were doing a regular pulldown. The range of motion will be more of an arc. During the movement, rotate your hands so that in the bottom position your palms face each other rather than forward. Return slowly to the starting position and repeat.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Gironda Sternum Chins', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Grasp the pull-up bar with a shoulder width underhand grip.','Now hang with your arms fully extended and stick your chest out and lean back. Tip: You will be leaning back throughout the entire movement. This will be your starting position.','Start pulling yourself towards the bar with your spine arched throughout the movement and your head leaning back as far away from the bar as possible. Exhale as you perform this portion of the movement. Tip: At the upper end of the movement, your hips and legs will be at about a 45-degree angle to the floor.','Keep pulling until your collarbone passes the bar and your lower chest or sternum area touches it. Hold that contraction for a second. Tip: By the time you''ve completed this portion of the movement; your head will be parallel to the floor.','Slowly start going back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Glute Ham Raise', 'machine', true, 'machine', 'intermediate', 'pull', 'compound', ARRAY['Begin by adjusting the equipment to fit your body. Place your feet against the footplate in between the rollers as you lie facedown. Your knees should be just behind the pad.','Start from the bottom of the movement. Keep your back arched as you begin the movement by flexing the knees. Drive your toes into the foot plate as you do so. Keep your upper body straight, and continue until your body is upright.','Return to the starting position, keeping your descent under control.'], ARRAY['hamstrings'], ARRAY['calves','glutes'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Glute Kickback', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Kneel on the floor or an exercise mat and bend at the waist with your arms extended in front of you (perpendicular to the torso) in order to get into a kneeling push-up position but with the arms spaced at shoulder width. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.','As you exhale, lift up your right leg until the hamstrings are in line with the back while maintaining the 90-degree angle bend. Contract the glutes throughout this movement and hold the contraction at the top for a second. Tip: At the end of the movement the upper leg should be parallel to the floor while the calf should be perpendicular to it.','Go back to the initial position as you inhale and now repeat with the left leg.','Continue to alternate legs until all of the recommended repetitions have been performed.'], ARRAY['glutes'], ARRAY['hamstrings'], ARRAY['On all fours or standing at cable','Drive heel straight back and up','Squeeze glute at top, hold 1 second','Dont arch lower back','Keep core engaged throughout'], ARRAY['Using lower back instead of glutes','Kicking too high','Going too fast'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Goblet Squat', 'kettlebells', true, 'kettlebells', 'beginner', 'push', 'compound', ARRAY['Stand holding a light kettlebell by the horns close to your chest. This will be your starting position.','Squat down between your legs until your hamstrings are on your calves. Keep your chest and head up and your back straight.','At the bottom position, pause and use your elbows to push your knees out. Return to the starting position, and repeat for 10-20 repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders'], ARRAY['Hold dumbbell at chest, elbows inside knees','Sit deep, use weight as counterbalance','Keep chest tall and proud','Great for learning proper squat pattern','Push knees out at the bottom'], ARRAY['Letting elbows flare out','Not going deep enough','Rounding upper back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Good Morning', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with a bar on a rack at shoulder height. Rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Step back from the rack.','Begin by bending at the hips, moving them back as you bend over to near parallel. Keep your back arched and your cervical spine in proper alignment.','Reverse the motion by extending through the hips with your glutes and hamstrings. Continue until you have returned to the starting position.'], ARRAY['hamstrings'], ARRAY['abdominals','glutes','lower back'], ARRAY['Bar on upper back like a squat','Hinge at hips, push butt back','Keep slight knee bend throughout','Go until you feel hamstring stretch','Drive hips forward to stand'], ARRAY['Rounding lower back','Going too heavy too soon','Bending knees too much (becomes a squat)','Looking up and straining neck'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Good Morning off Pins', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with a bar on a rack at about the same height as your stomach. Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.','Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight. Slowly lower the weight back to the pins returning to the starting position.'], ARRAY['hamstrings'], ARRAY['abdominals','glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Gorilla Chin/Crunch', 'body only', true, 'body only', 'intermediate', 'pull', 'compound', ARRAY['Hang from a chin-up bar using an underhand grip (palms facing you) that is slightly wider than shoulder width.','Now bend your knees at a 90 degree angle so that the calves are parallel to the floor while the thighs remain perpendicular to it. This will be your starting position.','As you exhale, pull yourself up while crunching your knees up at the same time until your knees are at chest level. You will stop going up as soon as your nose is at the same level as the bar. Tip: When you get to this point you should also be finishing the crunch at the same time.','Slowly start to inhale as you return to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hack Squat', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.','Position your legs in the platform using a shoulder width medium stance with the toes slightly pointed out. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Place your arms on the side handles of the machine and disengage the safety bars (which on most designs is done by moving the side handles from a facing front position to a diagonal position).','Now straighten your legs without locking the knees. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Begin to slowly lower the unit by bending the knees as you maintain a straight posture with the head up (back on the pad at all times). Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the unit as you exhale by pushing the floor with mainly with the heel of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY['Feet shoulder width on platform','Lower until thighs parallel','Push through heels','Isolates quads without lower back stress','Dont lock knees at top'], ARRAY['Feet too high on platform','Coming up on toes','Not controlling the descent'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hammer Curls', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.','The palms of the hands should be facing your torso. This will be your starting position.','Now, while holding your upper arm stationary, exhale and curl the weight forward while contracting the biceps. Continue to raise the weight until the biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief moment as you squeeze the biceps. Tip: Focus on keeping the elbow stationary and only moving your forearm.','After the brief pause, inhale and slowly begin the lower the dumbbells back down to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hammer Grip Incline DB Bench Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.','Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.','Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Handstand Push-Ups', 'body only', true, 'body only', 'expert', 'push', 'compound', ARRAY['With your back to the wall bend at the waist and place both hands on the floor at shoulder width.','Kick yourself up against the wall with your arms straight. Your body should be upside down with the arms and legs fully extended. Keep your whole body as straight as possible. Tip: If doing this for the first time, have a spotter help you. Also, make sure that you keep facing the wall with your head, rather than looking down.','Slowly lower yourself to the ground as you inhale until your head almost touches the floor. Tip: It is of utmost importance that you come down slow in order to avoid head injury.','Push yourself back up slowly as you exhale until your elbows are nearly locked.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hang Clean', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.','Begin by aggressively extending through the hips, knees and ankles, driving the weight upward. As you do so, shrug your shoulders towards your ears.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.'], ARRAY['quadriceps'], ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hang Clean - Below the Knees', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a shoulder width, double overhand or hook grip, with the bar hanging just below the knees. Your back should be straight and inclined slightly forward.','Begin by aggressively extending through the hips, knees and ankles, driving the weight upward. As you do so, shrug your shoulders towards your ears. As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out.','At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.'], ARRAY['quadriceps'], ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hang Snatch', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be at the hips. This will be your starting position.','Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.','Return to a standing position with the weight overhead. Follow by returning the weight to the ground under control.'], ARRAY['hamstrings'], ARRAY['abdominals','calves','forearms','glutes','lower back','quadriceps','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hang Snatch - Below Knees', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be just below the knees. This will be your starting position.','Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.','Return to a standing position with the weight overhead, and then return the weight to the floor under control.'], ARRAY['hamstrings'], ARRAY['abdominals','calves','forearms','glutes','lower back','quadriceps','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hanging Bar Good Morning', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with a bar on a rack at about the same height as your stomach. Suspend the bar using chains or suspension straps.','Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your traps. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.','Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight.','Slowly lower the weight back to the starting position, where it is supported by the chains.'], ARRAY['hamstrings'], ARRAY['abdominals','glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hanging Leg Raise', 'body only', true, 'body only', 'expert', 'pull', 'isolation', ARRAY['Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.','Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.','Go back slowly to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hanging Pike', 'body only', true, 'body only', 'expert', 'pull', 'compound', ARRAY['Hang from a chin-up bar with your legs and feet together using an overhand grip (palms facing away from you) that is slightly wider than shoulder width. Tip: You may use wrist wraps in order to facilitate holding on to the bar.','Now bend your knees at a 90 degree angle and bring the upper legs forward so that the calves are perpendicular to the floor while the thighs remain parallel to it. This will be your starting position.','Pull your legs up as you exhale until you almost touch your shins with the bar above you. Tip: Try to straighten your legs as much as possible while at the top.','Lower your legs as slowly as possible until you reach the starting position. Tip: Avoid swinging and using momentum at all times.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Heaving Snatch Balance', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['This drill helps you learn the snatch. Begin by holding a light weight across the back of the shoulders. Your feet should be slightly wider than hip width apart with the feet turned out, the same position that you would perform a squat with.','Begin by dipping with the knees slightly, and popping back up to briefly unload the bar. Drive yourself underneath the bar, elevating it overhead as you descend into a full squat.','Return to a standing position.'], ARRAY['quadriceps'], ARRAY['abdominals','forearms','glutes','hamstrings','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Heavy Bag Thrust', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Utilize a heavy bag for this exercise. Assume an upright stance next to the bag, with your feet staggered, fairly wide apart. Place your hand on the bag at about chest height. This will be your starting position.','Begin by twisting at the waist, pushing the bag forward as hard as possible. Perform this move quickly, pushing the bag away from your body.','Receive the bag as it swings back by reversing these steps.'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('High Cable Curls', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['Stand between a couple of high pulleys and grab a handle in each arm. Position your upper arms in a way that they are parallel to the floor with the palms of your hands facing you. This will be your starting position.','Curl the handles towards you until they are next to your ears. Make sure that as you do so you flex your biceps and exhale. The upper arms should remain stationary and only the forearms should move. Hold for a second in the contracted position as you squeeze the biceps.','Slowly bring back the arms to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hip Extension with Bands', 'bands', true, 'bands', 'beginner', 'push', 'compound', ARRAY['Secure one end of the band to the lower portion of a post and attach the other to one ankle.','Facing the attachment point of the band, hold on to the column to stabilize yourself.','Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight.','Return the leg to the starting position.'], ARRAY['glutes'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hip Flexion with Band', 'bands', true, 'bands', 'beginner', 'pull', 'compound', ARRAY['Secure one end of the band to the lower portion of a post and attach the other to one ankle.','Face away from the attachment point of the band.','Keeping your head and your chest up, raise your knee up to 90 degrees and pause.','Return the leg to the starting position.'], ARRAY['quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hip Lift with Band', 'bands', true, 'bands', 'beginner', 'push', 'compound', ARRAY['After choosing a suitable band, lay down in the middle of the rack, after securing the band on either side of you. If your rack doesn''t have pegs, the band can be secured using heavy dumbbells or similar objects, just ensure they won''t move.','Adjust your position so that the band is directly over your hips. Bend your knees and place your feet flat on the floor. Your hands can be on the floor or holding the band in position.','Keeping your shoulders on the ground, drive through your heels to raise your hips, pushing into the band as high as you can.','Pause at the top of the motion, and return to the starting position.'], ARRAY['glutes'], ARRAY['calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hurdle Hops', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Set up a row of hurdles or other small barriers, placing them a few feet apart.','Stand in front of the first hurdle with your feet shoulder width apart. This will be your starting position.','Begin by jumping with both feet over the first hurdle, swinging both arms as you jump.','Absorb the impact of landing by bending the knees, rebounding out of the first leap by jumping over the next hurdle. Continue until you have jumped over all of the hurdles.'], ARRAY['hamstrings'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hyperextensions (Back Extensions)', 'other', true, 'other', 'beginner', 'pull', 'isolation', ARRAY['Lie face down on a hyperextension bench, tucking your ankles securely under the footpads.','Adjust the upper pad if possible so your upper thighs lie flat across the wide pad, leaving enough room for you to bend at the waist without any restriction.','With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.','Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you feel a nice stretch on the hamstrings and you can no longer keep going without a rounding of the back. Tip: Never round the back as you perform this exercise. Also, some people can go farther than others. The key thing is that you go as far as your body allows you to without rounding the back.','Slowly raise your torso back to the initial position as you inhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.','Repeat for the recommended amount of repetitions.'], ARRAY['lower back'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Hyperextensions With No Hyperextension Bench', 'body only', true, 'body only', 'intermediate', 'pull', 'compound', ARRAY['With someone holding down your legs, slide yourself down to the edge a flat bench until your hips hang off the end of the bench. Tip: Your entire upper body should be hanging down towards the floor. Also, you will be in the same position as if you were on a hyperextension bench but the range of motion will be shorter due to the height of the flat bench vs. that of the hyperextension bench.','With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.','Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you almost touch the floor or you feel a nice stretch on the hamstrings (whichever comes first). Tip: Never round the back as you perform this exercise.','Slowly raise your torso back to the initial position as you exhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.','Repeat for the recommended amount of repetitions.'], ARRAY['lower back'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Incline Barbell Triceps Extension', 'barbell', true, 'barbell', 'intermediate', 'push', 'isolation', ARRAY['Hold a barbell with an overhand grip (palms down) that is a little closer together than shoulder width.','Lie back on an incline bench set at any angle between 45-75-degrees.','Bring the bar overhead with your arms extended and elbows in. The arms should be in line with the torso above the head. This will be your starting position.','Now lower the bar in a semicircular motion behind your head until your forearms touch your biceps. Inhale as you perform this movement. Tip: Keep your upper arms stationary and close to your head at all times. Only the forearms should move.','Return to the starting position as you breathe out and you contract the triceps. Hold the contraction for a second.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Incline Bench Pull', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Grab a dumbbell in each hand and lie face down on an incline bench that is set to an incline that is approximately 30 degrees.','Let the arms hang to your sides fully extended as they point to the floor.','Turn the wrists until your hands have a pronated (palms down) grip.','Now flare the elbows out. This will be your starting position.','As you breathe out, start to pull the dumbbells up as if you are doing a reverse bench press. You will do this by bending at the elbows and bringing the upper arms up as you let the forearms hang. Continue this motion until the upper arms are at the same level as your back. Tip: The elbows will come out to the side and your upper arms and torso should make the letter T at the top of the movement. Hold the contraction at the top for a second.','Slowly go back down to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Incline Cable Chest Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.','Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.','After pausing at full extension, return to the starting position, keeping tension on the cables.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Incline Cable Flye', 'cable', true, 'cable', 'intermediate', 'push', 'isolation', ARRAY['To get yourself into the starting position, set the pulleys at the floor level (lowest level possible on the machine that is below your torso).','Place an incline bench (set at 45 degrees) in between the pulleys, select a weight on each one and grab a pulley on each hand.','With a handle on each hand, lie on the incline bench and bring your hands together at arms length in front of your face. This will be your starting position.','With a slight bend of your elbows (in order to prevent stress at the biceps tendon), lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary. The movement should only occur at the shoulder joint.','Return your arms back to the starting position as you squeeze your chest muscles and exhale. Hold the contracted position for a second. Tip: Make sure to use the same arc of motion used to lower the weights.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Incline Dumbbell Bench With Palms Facing In', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.','Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.','Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Incline Dumbbell Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.','While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.','Slowly begin to bring the dumbbells back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
